#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <omp.h>

#define RADIUS 7
#define BLOCK_SIZE 256

void stencil_1d(const int *in, int *out, int length) {
  int total_threads = length;

  #pragma omp parallel for
  for (int block_idx = 0; block_idx < length / BLOCK_SIZE; ++block_idx) {
    int gindex_base = block_idx * BLOCK_SIZE;

    // Shared buffer simulation using local array (since OpenMP threads in a team share scope differently)
    // We use a local array per block logic, but in OpenMP we typically just compute directly or use careful indexing.
    // To mimic the CUDA shared memory behavior exactly for correctness:
    // Each thread group (block) needs to handle its own window.

    // Since OpenMP doesn't have explicit "blocks" with shared memory in the same way,
    // we will implement the logic using a temporary buffer allocated per block or recompute.
    // However, to stay efficient and correct, we'll use a local array inside the parallel region 
    // but scoped per block iteration.

    int temp[BLOCK_SIZE + 2 * RADIUS];

    // Simulate block-level execution
    for (int t = 0; t < BLOCK_SIZE; ++t) {
      int gindex = gindex_base + t;
      int lindex = t + RADIUS;

      temp[lindex] = in[gindex];

      if (t < RADIUS) {
        temp[lindex - RADIUS] = (gindex < RADIUS) ? 0 : in[gindex - RADIUS];
        if (gindex + BLOCK_SIZE < length) {
          temp[lindex + BLOCK_SIZE] = in[gindex + BLOCK_SIZE];
        } else {
          // Handle boundary if needed, though original CUDA code assumes valid access
          // Based on original: temp[lindex + BLOCK_SIZE] = in[gindex + BLOCK_SIZE];
          // If gindex + BLOCK_SIZE is out of bounds, this would be an error in original too unless length is padded.
          // The original code allocates pad_size = (length + RADIUS), so gindex + BLOCK_SIZE might be safe if length is multiple of BLOCK_SIZE and padded.
          // But strictly following original logic:
          temp[lindex + BLOCK_SIZE] = (gindex + BLOCK_SIZE < length + RADIUS) ? in[gindex + BLOCK_SIZE] : 0;
        }
      }
    }

    // Now compute results for this block
    for (int t = 0; t < BLOCK_SIZE; ++t) {
      int gindex = gindex_base + t;
      int lindex = t + RADIUS;

      int result = 0;
      for (int offset = -RADIUS; offset <= RADIUS; ++offset) {
        result += temp[lindex + offset];
      }
      out[gindex] = result;
    }
  }
}

int main(int argc, char* argv[]) {
  if (3 != argc) {
    printf("Usage: %s <length> <repeat>\n", argv[0]);
    printf("length is a multiple of %d\n", BLOCK_SIZE);
    return 1;
  }
  const int length = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  int size = length * sizeof(int);
  int pad_size = (length + RADIUS) * sizeof(int);

  int *a, *b;

  a = (int *)malloc(pad_size); 
  b = (int *)malloc(size);

  for (int i = 0; i < length + RADIUS; i++) a[i] = i;

  // Initialize b to 0 just in case, though not strictly required by algorithm
  for (int i = 0; i < length; i++) b[i] = 0;

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    stencil_1d(a, b, length);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  bool ok = true;
  for (int i = 0; i < 2*RADIUS; i++) {
    int s = 0;
    for (int j = i; j <= i+2*RADIUS; j++) {
      if (j < RADIUS) {
        s += 0;
      } else {
        s += (a[j - RADIUS]);
      }
    }
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }

  for (int i = 2*RADIUS; i < length; i++) {
    int s = 0;
    for (int j = i-RADIUS; j <= i+RADIUS; j++) {
      s += a[j];
    }
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(a);
  free(b); 

  return 0;
}
